-- bb-lesson-intro: Introduction
UPDATE lessons SET content_json = '{"sections": [{"title": "Introduction", "content": "In this program you will model and create a robust ball and beam controller by creating an engineering model, designing control loop architecture, and deploying code on a real control system.\n\nYou''ll work with a collection of 3D printed parts, electronics, and a wooden platform originally developed by Ian Carey. This project will help you develop an understanding of control theory, physics, and software written in Python and C++. It includes a combination of model-based design and hands-on testing which are techniques used in industry for designing and deploying control systems.\n\nThroughout the program you''ll build your project incrementally using provided training materials, reference implementations, and various examples. These resources are designed to support you without removing the need for engineering decision making.\n\nIf you need help, email support@shortcct.com with your specific questions and a zip file including any files relevant to your project. Remember, virtual support is available for 3 months after your product delivery date."}], "key_points": ["Create a ball and beam controller with engineering model", "Combine model-based design with hands-on testing", "Uses Python and C++ for control systems", "Support available at support@shortcct.com for 3 months"], "resources": []}' WHERE id = 'bb-lesson-intro';

-- bb-lesson-background: Recommended Background
UPDATE lessons SET content_json = '{"sections": [{"title": "Recommended Background", "content": "This project is designed for students who want hands-on control and embedded systems experience. You do not need a lot of experience, but some foundational knowledge is expected.\n\n**Required:**\n- Introductory programming experience in C++ or Python\n- Basic knowledge of electronics\n\n**Helpful:**\n- Introductory exposure to embedded systems\n- Basic understanding of physics and signal theory\n\nIf you find that you are missing some of this background, reach out to us at support@shortcct.com and we can explore options to get you up to speed!"}], "key_points": ["Requires basic C++ or Python programming", "Basic electronics knowledge needed", "Physics and signal theory helpful but not required"], "resources": []}' WHERE id = 'bb-lesson-background';

-- bb-lesson-industry: Industry Alignment
UPDATE lessons SET content_json = '{"sections": [{"title": "Industry Alignment", "content": "We analyzed the most in-demand skills across 50+ companies hiring embedded systems engineering interns. Below is how the Ball and Beam Project aligns with those skills.\n\n- **Core skills** are fully covered in the base project.\n- **Extendable skills** can be developed through optional project extensions and the design challenge.\n- **Not Covered** indicates skills that are outside the scope of the core project."}, {"title": "Documentation", "content": "**Useful Resources:**\n- Control Stepper Motor with DRV8825 Driver Module & Arduino - Last Minute Engineers\n- How HC-SR04 Ultrasonic Sensor Works & Interface It With Arduino - Last Minute Engineers\n- Control Tutorials for MATLAB and Simulink - Ball & Beam: System Modeling"}], "key_points": ["Skills aligned with 50+ embedded systems employers", "Core skills fully covered in base project", "Extendable skills through design challenge"], "resources": [{"title": "DRV8825 Stepper Motor Tutorial", "url": "https://lastminuteengineers.com/drv8825-stepper-motor-driver-arduino-tutorial/", "type": "external"}, {"title": "HC-SR04 Ultrasonic Sensor Tutorial", "url": "https://lastminuteengineers.com/arduino-sr04-ultrasonic-sensor-tutorial/", "type": "external"}, {"title": "Ball & Beam System Modeling", "url": "https://ctms.engin.umich.edu/CTMS/index.php?example=BallBeam&section=SystemModeling", "type": "external"}]}' WHERE id = 'bb-lesson-industry';

-- bb-lesson-t-overview: Complete Project Overview
UPDATE lessons SET content_json = '{"sections": [{"title": "Project Overview", "content": "The Ball and Beam project teaches you to design and implement a closed-loop control system. You will:\n\n1. **Understand the hardware** - 3D printed parts, electronics, and wooden platform\n2. **Learn control theory** - PID control, feedback loops, and system modeling\n3. **Write embedded software** - Real-time control loops in C++\n4. **Test and tune** - Hands-on calibration and performance optimization\n\nThis video provides a complete overview of the project and what you will accomplish."}], "key_points": ["Closed-loop control system implementation", "Combines hardware and software skills", "Real-time embedded programming", "Hands-on testing and tuning"], "resources": []}' WHERE id = 'bb-lesson-t-overview';

