-- bb-lesson-task1: Task 1: Implement the Real-Time Control Loop
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Configure a fixed-interval control loop that runs deterministically. The loop should execute at a consistent sampling rate (for example, every 10 ms). All sensing, PID computation, and actuator updates must occur inside this timed loop."}, {"title": "Implementation Guidance", "content": "- Use a non-blocking timing method (such as `millis()` or a hardware timer) to maintain a constant loop interval\n- Store the loop interval in seconds for proper integral and derivative calculation\n- Ensure that sensor readings are filtered before entering the PID equation\n- Print loop timing and position values to Serial during early testing\n\n```cpp\nconst unsigned long LOOP_INTERVAL_MS = 10;  // 10ms = 100Hz\nconst float dt = LOOP_INTERVAL_MS / 1000.0; // Convert to seconds\n\nunsigned long previousTime = 0;\n\nvoid setup() {\n    Serial.begin(115200);\n    initSensor();\n    initMotor();\n}\n\nvoid loop() {\n    unsigned long currentTime = millis();\n    \n    if (currentTime - previousTime >= LOOP_INTERVAL_MS) {\n        previousTime = currentTime;\n        \n        // 1. Read and filter sensor\n        float position = readFilteredPosition();\n        \n        // 2. Compute PID output\n        float output = computePID(setpoint, position, dt);\n        \n        // 3. Update actuator\n        setMotorOutput(output);\n        \n        // Debug output\n        Serial.print(\"Pos: \");\n        Serial.print(position);\n        Serial.print(\" Out: \");\n        Serial.println(output);\n    }\n}\n```"}, {"title": "Key Requirements", "content": "- Loop must run at consistent intervals (10ms recommended)\n- All control code inside the timed section\n- dt stored in seconds for PID calculations\n- Sensor filtering before PID computation"}], "key_points": ["Use non-blocking timing with millis()", "10ms loop interval = 100Hz sampling rate", "Store dt in seconds for PID math", "Filter sensor readings before PID"], "resources": []}' WHERE id = 'bb-lesson-task1';

-- bb-lesson-task2: Task 2: Implement the PID Algorithm
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Write the PID controller logic using proportional, integral, and derivative terms. The controller should compute the control output based on the error between the setpoint and measured ball position."}, {"title": "Implementation Guidance", "content": "- Define global variables for Kp, Ki, and Kd\n- Compute error as setpoint minus measured position\n- Accumulate the integral term using error multiplied by dt\n- Compute the derivative term using the change in error divided by dt\n- Store the previous error for the next iteration\n- Constrain the control output to safe actuator limits\n- Implement integral windup protection by clamping the integral term\n\n```cpp\n// controller.h\n#ifndef CONTROLLER_H\n#define CONTROLLER_H\n\nvoid initController(float kp, float ki, float kd);\nfloat computePID(float setpoint, float measured, float dt);\nvoid resetController();\n\n#endif\n```\n\n```cpp\n// controller.cpp\n#include \"controller.h\"\n\nstatic float Kp, Ki, Kd;\nstatic float previousError = 0;\nstatic float integral = 0;\n\nconst float INTEGRAL_MAX = 100.0;  // Anti-windup limit\nconst float OUTPUT_MAX = 255.0;\nconst float OUTPUT_MIN = -255.0;\n\nvoid initController(float kp, float ki, float kd) {\n    Kp = kp;\n    Ki = ki;\n    Kd = kd;\n    resetController();\n}\n\nvoid resetController() {\n    previousError = 0;\n    integral = 0;\n}\n\nfloat computePID(float setpoint, float measured, float dt) {\n    // Calculate error\n    float error = setpoint - measured;\n    \n    // Proportional term\n    float P = Kp * error;\n    \n    // Integral term with anti-windup\n    integral += error * dt;\n    if (integral > INTEGRAL_MAX) integral = INTEGRAL_MAX;\n    if (integral < -INTEGRAL_MAX) integral = -INTEGRAL_MAX;\n    float I = Ki * integral;\n    \n    // Derivative term\n    float derivative = (error - previousError) / dt;\n    float D = Kd * derivative;\n    previousError = error;\n    \n    // Compute total output\n    float output = P + I + D;\n    \n    // Constrain to actuator limits\n    if (output > OUTPUT_MAX) output = OUTPUT_MAX;\n    if (output < OUTPUT_MIN) output = OUTPUT_MIN;\n    \n    return output;\n}\n```"}, {"title": "Anti-Windup Protection", "content": "Integral windup occurs when the integral term accumulates to very large values during sustained errors (e.g., when the ball is stuck or the system is saturated). This can cause massive overshoot when the error finally reduces.\n\n**Solution:** Clamp the integral term to a maximum value to prevent runaway accumulation."}], "key_points": ["Error = setpoint - measured", "Integral accumulates error * dt", "Derivative = (error - previousError) / dt", "Constrain output to safe limits", "Implement anti-windup for integral term"], "resources": []}' WHERE id = 'bb-lesson-task2';

-- bb-lesson-task3: Task 3: Integrate the Motor Driver
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Convert the PID output into a valid actuator command that safely drives the motor or servo controlling the beam."}, {"title": "Implementation Guidance", "content": "- Map the PID output to a PWM value or servo angle\n- Respect mechanical angle limits of the beam\n- Ensure smooth transitions when switching motor direction\n- Test actuator response independently before running full PID control\n- Add safety constraints to prevent sustained maximum output\n\n**For Servo Motor:**\n```cpp\n// actuator.h\n#ifndef ACTUATOR_H\n#define ACTUATOR_H\n\nvoid initActuator();\nvoid setBeamAngle(float pidOutput);\n\n#endif\n```\n\n```cpp\n// actuator.cpp\n#include \"actuator.h\"\n#include <Servo.h>\n\nServo beamServo;\nconst int SERVO_PIN = 9;\nconst int CENTER_ANGLE = 90;\nconst int MAX_DEFLECTION = 30;  // +/- 30 degrees from center\n\nvoid initActuator() {\n    beamServo.attach(SERVO_PIN);\n    beamServo.write(CENTER_ANGLE);\n}\n\nvoid setBeamAngle(float pidOutput) {\n    // Map PID output (-255 to 255) to angle deflection\n    float deflection = map(pidOutput, -255, 255, \n                          -MAX_DEFLECTION, MAX_DEFLECTION);\n    \n    // Calculate final angle\n    int angle = CENTER_ANGLE + (int)deflection;\n    \n    // Enforce limits\n    if (angle > CENTER_ANGLE + MAX_DEFLECTION) \n        angle = CENTER_ANGLE + MAX_DEFLECTION;\n    if (angle < CENTER_ANGLE - MAX_DEFLECTION) \n        angle = CENTER_ANGLE - MAX_DEFLECTION;\n    \n    beamServo.write(angle);\n}\n```\n\n**For DC Motor with H-Bridge:**\n```cpp\nvoid setMotorOutput(float pidOutput) {\n    int pwmValue = abs((int)pidOutput);\n    if (pwmValue > 255) pwmValue = 255;\n    \n    if (pidOutput > 0) {\n        // Forward direction\n        digitalWrite(DIR_PIN_A, HIGH);\n        digitalWrite(DIR_PIN_B, LOW);\n    } else {\n        // Reverse direction\n        digitalWrite(DIR_PIN_A, LOW);\n        digitalWrite(DIR_PIN_B, HIGH);\n    }\n    \n    analogWrite(MOTOR_PWM_PIN, pwmValue);\n}\n```"}, {"title": "Testing Before Integration", "content": "Before running the full PID controller:\n\n1. Test servo/motor with fixed angles/speeds\n2. Verify direction matches expected behavior\n3. Identify mechanical limits and dead zones\n4. Check for smooth motion without jerking"}], "key_points": ["Map PID output to actuator range", "Respect mechanical limits", "Test actuator independently first", "Handle direction changes smoothly"], "resources": []}' WHERE id = 'bb-lesson-task3';

-- bb-lesson-task4: Task 4: Tune the Controller
UPDATE lessons SET content_json = '{"sections": [{"title": "Objective", "content": "Tune the PID gains manually to achieve stable and responsive behavior."}, {"title": "Tuning Process", "content": "**Step 1: Start with zeros**\n- Set Ki = 0 and Kd = 0\n- Start with small Kp (e.g., Kp = 0.5)\n\n**Step 2: Increase Kp**\n- Gradually increase Kp until the system begins to oscillate\n- Note the value where oscillation starts\n- Back off slightly (use about 50-70% of that value)\n\n**Step 3: Add Kd**\n- Introduce Kd to reduce oscillation and improve damping\n- Start small (e.g., Kd = 0.1 * Kp)\n- Increase until oscillations are damped\n\n**Step 4: Add Ki**\n- Add a small Ki to eliminate steady-state error\n- Start very small (e.g., Ki = 0.01 * Kp)\n- Increase slowly - too much causes overshoot\n\n**Key Rules:**\n- Change ONE gain at a time\n- Observe system response after each change\n- Record all values and observations"}, {"title": "Tuning Table Template", "content": "| Kp | Ki | Kd | Observation |\n|-----|-----|-----|-------------|\n| 0.5 | 0 | 0 | Slow response, no oscillation |\n| 1.0 | 0 | 0 | Faster, slight oscillation |\n| 2.0 | 0 | 0 | Strong oscillation |\n| 1.5 | 0 | 0 | Good response, some overshoot |\n| 1.5 | 0 | 0.2 | Reduced overshoot |\n| 1.5 | 0 | 0.3 | Damped well, slight error |\n| 1.5 | 0.05 | 0.3 | Error eliminated |\n\nFinal values: Kp = 1.5, Ki = 0.05, Kd = 0.3"}, {"title": "Common Issues and Solutions", "content": "**Problem: System oscillates continuously**\n- Solution: Decrease Kp, increase Kd\n\n**Problem: System is sluggish**\n- Solution: Increase Kp\n\n**Problem: Ball settles slightly off-center**\n- Solution: Increase Ki (but be careful!)\n\n**Problem: Erratic, jerky motion**\n- Solution: Check sensor filtering, decrease Kd\n\n**Problem: Massive overshoot**\n- Solution: Decrease Ki, increase Kd"}], "key_points": ["Start with Kp only (Ki=0, Kd=0)", "Increase Kp until oscillation, then back off", "Add Kd to damp oscillations", "Add small Ki to eliminate steady-state error", "Change one gain at a time"], "resources": []}' WHERE id = 'bb-lesson-task4';

-- bb-lesson-demo: Controller Implementation Demo
UPDATE lessons SET content_json = '{"sections": [{"title": "Demo Requirements", "content": "Submit a video demonstrating your working Ball and Beam controller.\n\n**Video should show:**\n1. System stabilizing ball at center setpoint\n2. Recovery from small disturbances (gently push the ball)\n3. Serial output showing position and control values\n4. Smooth, stable operation without excessive oscillation"}, {"title": "File Structure", "content": "All code for this module must be implemented using the following structure:\n\n```\nproject/\n├── controller.h      # PID calculations and gain management\n├── controller.cpp\n├── actuator.h        # Motor or servo control\n├── actuator.cpp\n├── sensor.h          # Filtered position measurement\n├── sensor.cpp\n└── main.cpp          # System initialization and control loop\n```\n\n**Important:** No PID calculations, filtering logic, or motor control code should be written directly inside main.cpp beyond high-level coordination."}, {"title": "Submission Checklist", "content": "- [ ] Video demonstrating stable ball control\n- [ ] Ball recovers from disturbances\n- [ ] Code follows required file structure\n- [ ] PID gains documented with tuning observations\n- [ ] Sensor filtering implemented\n- [ ] Clean, readable code with comments"}], "key_points": ["Show stable control at setpoint", "Demonstrate disturbance recovery", "Follow required file structure", "Document final PID gains"], "resources": []}' WHERE id = 'bb-lesson-demo';
